module top_module(
	input wire[3:0] num,
	input wire en, dp, sign,
	output wire[7:0] hex
);reg [6:0] obf_sseg;

	always @*
	begin
		if (~en)
			obf_sseg <= 7'b0000000;
		else if (sign)
			obf_sseg <= 7'b1000000;
		else
			case (num)
				4'h0: obf_sseg <= 7'b0111111;
				4'h1: obf_sseg <= 7'b0000110;
				4'h2: obf_sseg <= 7'b1011011;
				4'h3: obf_sseg <= 7'b1001111;
				4'h4: obf_sseg <= 7'b1100110;
				4'h5: obf_sseg <= 7'b1101101;
				4'h6: obf_sseg <= 7'b1111101;
				4'h7: obf_sseg <= 7'b0000111;
				4'h8: obf_sseg <= 7'b1111111;
				4'h9: obf_sseg <= 7'b1101111;
				4'ha: obf_sseg <= 7'b1110111;
				4'hb: obf_sseg <= 7'b1111100;
				4'hc: obf_sseg <= 7'b1011000;
				4'hd: obf_sseg <= 7'b1011110;
				4'he: obf_sseg <= 7'b1111001;
				4'hf: obf_sseg <= 7'b1110001;
				default: obf_sseg <= 7'b1010011;
			endcase
	end

	assign hex = { (dp & en), obf_sseg };

endmodule
